import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ActivatedRoute, Router, RouterLink } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { combineLatest, map } from 'rxjs';
import { Item } from '../../core/models';

@Component({
  selector: 'app-admin-items',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './admin-items.component.html',
  styleUrls: ['./admin-items.component.css'],
})
export class AdminItemsComponent {
  form: FormGroup;
  saving = signal(false);

  readonly items = signal<Item[]>([
    { id: '1', sku: 'SR-1001', name: 'Steel Bolt M6', description: 'Zinc-plated hex bolt', unit: 'pcs', reorderAt: 100, totalQty: 340 },
    { id: '2', sku: 'SR-1002', name: 'Hex Nut M6', description: 'Standard hex nut', unit: 'pcs', reorderAt: 100, totalQty: 80 },
    { id: '4', sku: 'SR-1004', name: 'PVC Pipe 20mm', description: 'Rigid PVC conduit', unit: 'm', reorderAt: 40, totalQty: 15 },
    { id: '6', sku: 'SR-1006', name: 'LED Panel 40W', description: 'Ceiling LED panel', unit: 'pcs', reorderAt: 20, totalQty: 12 },
  ]);

  private readonly ctx = toSignal(
    combineLatest([this.route.paramMap, this.route.queryParamMap]).pipe(
      map(([p, q]) => ({ id: p.get('id'), isNew: q.get('form') === 'new' })),
    ),
    { initialValue: { id: null as string | null, isNew: false } },
  );

  readonly editId = computed(() => this.ctx().id);
  readonly showForm = computed(() => this.ctx().isNew || !!this.ctx().id);
  readonly editing = computed<Item | undefined>(() =>
    this.editId() ? this.items().find((i) => i.id === this.editId()) : undefined,
  );

  constructor(
    private fb: FormBuilder,
    private route: ActivatedRoute,
    private router: Router,
  ) {
    this.form = this.fb.group({
      sku: ['', Validators.required],
      name: ['', Validators.required],
      description: [''],
      unit: ['pcs', Validators.required],
      reorderAt: [0, [Validators.required, Validators.min(0)]],
    });
    // Populate form when navigating to an edit route.
    this.route.paramMap.subscribe(() => {
      const item = this.editing();
      if (item) {
        this.form.patchValue({
          sku: item.sku, name: item.name, description: item.description,
          unit: item.unit, reorderAt: item.reorderAt,
        });
      } else {
        this.form.reset({ sku: '', name: '', description: '', unit: 'pcs', reorderAt: 0 });
      }
    });
  }

  save(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    this.saving.set(true);
    setTimeout(() => {
      this.saving.set(false);
      this.router.navigate(['/admin/items']);
    }, 300);
  }

  remove(item: Item): void {
    this.items.update((list) => list.filter((i) => i.id !== item.id));
  }

  cancel(): void {
    this.router.navigate(['/admin/items']);
  }
}
